 38→/**
 39→ * Emit a structured progress line to stderr for MCP progress notifications.
 40→ * Only emits when running under an orchestrator (e.g., MCP server).
 41→ * The MCP handler parses these lines to send `notifications/progress`.
 42→ *
 43→ * @param issue - GitHub issue number
 44→ * @param phase - Phase name (e.g., "spec", "exec", "qa")
 45→ * @param event - Phase lifecycle event: "start", "complete", or "failed"
 46→ * @param extra - Optional fields: durationSeconds (on complete), error (on failed)
 47→ */
 48→export function emitProgressLine(
 49→  issue: number,
 50→  phase: string,
 51→  event: "start" | "complete" | "failed" = "start",
 52→  extra?: { durationSeconds?: number; error?: string },
 53→): void {
 54→  if (!process.env.SEQUANT_ORCHESTRATOR) return;
 55→  const payload: Record<string, unknown> = { issue, phase, event };
 56→  if (extra?.durationSeconds !== undefined) {
 57→    payload.durationSeconds = extra.durationSeconds;
 58→  }
 59→  if (extra?.error !== undefined) {
 60→    payload.error = extra.error;
 61→  }
