170→/**
171→ * Check if an issue has UI-related labels
172→ */
173→export function hasUILabels(labels: string[]): boolean {
174→  return labels.some((label) =>
175→    UI_LABELS.some((uiLabel) => label.toLowerCase().includes(uiLabel)),
176→  );
177→}
