 298→/**
 299→ * Parse batch arguments into groups of issues
 300→ */
 301→export function parseBatches(batchArgs: string[]): number[][] {
 302→  return batchArgs.map((batch) =>
 303→    batch
 304→      .split(/\s+/)
 305→      .map((n) => parseInt(n, 10))
 306→      .filter((n) => !isNaN(n)),
 307→  );
 308→}
