  1→/**
  2→ * Assess Comment Parser
  3→ *
  4→ * Detects and parses /assess command output from GitHub issue comments.
  5→ * This is the unified parser that handles both the new /assess format
  6→ * and the legacy /solve format for backward compatibility.
  7→ *
  8→ * When an assess comment exists, its phase recommendations take precedence
  9→ * over content analysis (but not over labels).
 10→ *
 11→ * @example
 12→ * ```typescript
 13→ * import { findAssessComment, parseAssessWorkflow } from './assess-comment-parser';
 14→ *
 15→ * const comments = [
 16→ *   { body: "Some regular comment" },
 17→ *   { body: "## Assess Analysis\n\n→ PROCEED — Ready.\n\n<!-- assess:phases=spec,exec,qa -->" },
 18→ * ];
 19→ *
 20→ * const assessComment = findAssessComment(comments);
 21→ * if (assessComment) {
 22→ *   const workflow = parseAssessWorkflow(assessComment.body);
 23→ *   // workflow: { phases: ['spec', 'exec', 'qa'], action: 'PROCEED', ... }
 24→ * }
 25→ * ```
 26→ */
 27→
 28→import type { Phase } from "./workflow/types.js";
 29→import type { PhaseSignal } from "./phase-signal.js";
 30→
 31→/**
 32→ * The 6 fixed actions that /assess can recommend
 33→ */
 34→export type AssessAction =
 35→  | "PROCEED"
 36→  | "CLOSE"
 37→  | "MERGE"
 38→  | "REWRITE"
 39→  | "CLARIFY"
 40→  | "PARK";
 41→
 42→/**
 43→ * Result of parsing an assess comment (superset of SolveWorkflowResult)
 44→ */
 45→export interface AssessWorkflowResult {
 46→  /** Phases recommended by assess (only meaningful for PROCEED) */
 47→  phases: Phase[];
 48→  /** Whether quality loop is recommended */
 49→  qualityLoop: boolean;
 50→  /** The issue numbers mentioned in the assess comment */
 51→  issueNumbers: number[];
 52→  /** Raw workflow string (e.g., "spec → exec → qa") */
 53→  workflowString?: string;
 54→  /** The recommended action (one of the 6 fixed actions) */
 55→  action?: AssessAction;
 56→}
 57→
 58→/**
 59→ * Backward-compatible alias for AssessWorkflowResult
 60→ */
 61→export type SolveWorkflowResult = AssessWorkflowResult;
 62→
 63→/**
 64→ * Comment structure (simplified from GitHub API)
 65→ */
 66→export interface IssueComment {
 67→  body: string;
 68→  author?: {
 69→    login: string;
 70→  };
 71→  createdAt?: string;
 72→}
 73→
 74→/**
 75→ * Markers that indicate an assess comment (new format)
 76→ */
 77→const ASSESS_MARKERS = [
 78→  "## Assess Analysis",
 79→  "## Assess Workflow",
 80→  "*Generated by `/assess",
 81→];
 82→
 83→/**
 84→ * Markers that indicate a solve comment (legacy format)
 85→ */
 86→const SOLVE_MARKERS = [
 87→  "## Solve Analysis",
 88→  "## Solve Workflow for Issues:",
 89→  "## Solve Workflow for Issue:",
 90→  "### Recommended Workflow",
 91→  "*📝 Generated by `/solve",
 92→];
 93→
 94→/**
 95→ * All markers (both assess and solve)
 96→ */
 97→const ALL_MARKERS = [...ASSESS_MARKERS, ...SOLVE_MARKERS];
 98→
 99→/**
100→ * Pattern to extract phases from workflow string
101→ * Matches: `/spec`, `/exec`, `/test`, `/qa`, etc.
102→ * Also matches without slash: `spec`, `exec`, `test`, `qa` (for arrow notation)
103→ */
104→const PHASE_PATTERN =
105→  /\/?(?<!\w)(spec|exec|test|qa|security-review|testgen|loop)(?!\w)/g;
106→
107→/**
108→ * Pattern to detect quality loop recommendation
109→ */
110→const QUALITY_LOOP_PATTERNS = [
111→  /quality\s*loop.*auto-enable/i,
112→  /--quality-loop/i,
113→  /quality\s*loop.*recommended/i,
114→  /enable.*quality\s*loop/i,
115→];
116→
117→/**
118→ * Pattern to extract structured data from HTML comment markers
119→ * Matches both: <!-- assess:phases=exec,qa --> and <!-- solve:phases=exec,qa -->
120→ */
121→const HTML_MARKER_PATTERN =
122→  /<!--\s*(?:assess|solve):(\w[\w-]*)=([\w,.-]*)\s*-->/g;
123→
124→/**
125→ * Pattern to extract assess-specific HTML markers (takes precedence)
126→ */
127→const ASSESS_HTML_MARKER_PATTERN = /<!--\s*assess:(\w[\w-]*)=([\w,.-]*)\s*-->/g;
128→
129→/**
130→ * Pattern to extract issue numbers from header
131→ * Matches: "## Solve Workflow for Issues: 123, 456" or "#123"
132→ */
133→const ISSUE_NUMBER_PATTERN = /#?(\d+)/g;
134→
135→/**
136→ * Valid assess actions
137→ */
138→const VALID_ACTIONS: AssessAction[] = [
139→  "PROCEED",
140→  "CLOSE",
141→  "MERGE",
142→  "REWRITE",
143→  "CLARIFY",
144→  "PARK",
145→];
146→
147→/**
148→ * Structured data extracted from HTML comment markers
149→ */
150→export interface AssessMarkers {
151→  /** Recommended phases */
152→  phases?: string[];
153→  /** Whether browser testing is needed */
154→  browserTest?: boolean;
155→  /** Whether quality loop is recommended */
156→  qualityLoop?: boolean;
157→  /** The recommended action */
158→  action?: AssessAction;
159→}
160→
161→/**
162→ * Backward-compatible alias for AssessMarkers
163→ */
164→export type SolveMarkers = AssessMarkers;
165→
166→// ─── Detection Functions ────────────────────────────────────────────────────
167→
168→/**
169→ * Check if a comment is an assess command output (new format)
170→ */
171→export function isAssessComment(body: string): boolean {
172→  return ALL_MARKERS.some((marker) => body.includes(marker));
173→}
174→
175→/**
176→ * Check if a comment is a solve command output (legacy format)
177→ * @deprecated Use isAssessComment instead
178→ */
179→export function isSolveComment(body: string): boolean {
180→  return isAssessComment(body);
181→}
182→
183→/**
184→ * Find the most recent assess/solve comment from a list of comments
185→ */
186→export function findAssessComment(
187→  comments: IssueComment[],
188→): IssueComment | null {
189→  for (let i = comments.length - 1; i >= 0; i--) {
190→    if (isAssessComment(comments[i].body)) {
191→      return comments[i];
192→    }
193→  }
194→  return null;
195→}
196→
197→/**
198→ * Find the most recent solve comment from a list of comments
199→ * @deprecated Use findAssessComment instead
200→ */
201→export function findSolveComment(
202→  comments: IssueComment[],
203→): IssueComment | null {
204→  return findAssessComment(comments);
205→}
206→
207→// ─── Parsing Functions ──────────────────────────────────────────────────────
208→
209→/**
210→ * Parse phases from a workflow string
211→ */
212→function parseWorkflowString(workflowString: string): Phase[] {
213→  const phases: Phase[] = [];
214→  const matches = workflowString.matchAll(PHASE_PATTERN);
215→
216→  for (const match of matches) {
217→    const phase = match[1] as Phase;
218→    if (!phases.includes(phase)) {
219→      phases.push(phase);
220→    }
221→  }
222→
223→  return phases;
224→}
225→
226→/**
227→ * Parse HTML comment markers from a comment body
228→ *
229→ * Supports both `assess:` and `solve:` prefixes.
230→ * When both are present, `assess:` markers take precedence.
231→ */
232→export function parseAssessMarkers(body: string): AssessMarkers {
233→  const markers: AssessMarkers = {};
234→
235→  // First pass: collect all markers (both assess: and solve:)
236→  const allMatches = body.matchAll(HTML_MARKER_PATTERN);
237→  for (const match of allMatches) {
238→    applyMarker(markers, match[1], match[2]);
239→  }
240→
241→  // Second pass: assess: markers override solve: markers
242→  const assessMatches = body.matchAll(ASSESS_HTML_MARKER_PATTERN);
243→  for (const match of assessMatches) {
244→    applyMarker(markers, match[1], match[2]);
245→  }
246→
247→  return markers;
248→}
249→
250→/**
251→ * Apply a single marker key-value pair to the markers object
252→ */
253→function applyMarker(markers: AssessMarkers, key: string, value: string): void {
254→  switch (key) {
255→    case "phases":
256→      markers.phases = value.split(",").filter(Boolean);
257→      break;
258→    case "browser-test":
259→      markers.browserTest = value === "true";
260→      break;
261→    case "quality-loop":
262→      markers.qualityLoop = value === "true";
263→      break;
264→    case "action":
265→      if (VALID_ACTIONS.includes(value as AssessAction)) {
266→        markers.action = value as AssessAction;
267→      }
268→      break;
269→  }
270→}
271→
272→/**
273→ * Parse HTML comment markers (backward-compatible alias)
274→ * @deprecated Use parseAssessMarkers instead
275→ */
276→export function parseSolveMarkers(body: string): AssessMarkers {
277→  return parseAssessMarkers(body);
278→}
279→
280→/**
281→ * Parse an assess/solve comment to extract workflow information
282→ */
283→export function parseAssessWorkflow(body: string): AssessWorkflowResult {
284→  const result: AssessWorkflowResult = {
285→    phases: [],
286→    qualityLoop: false,
287→    issueNumbers: [],
288→  };
289→
290→  // Extract action from "→ ACTION — reason" line
291→  const actionMatch = body.match(
292→    /→\s*(PROCEED|CLOSE|MERGE|REWRITE|CLARIFY|PARK)\s*[—-]/,
293→  );
294→  if (actionMatch) {
295→    result.action = actionMatch[1] as AssessAction;
296→  }
297→
298→  // Extract issue numbers from header (both old and new formats)
299→  const headerMatch = body.match(
300→    /## (?:Assess|Solve) (?:Workflow for Issues?|Analysis)(?::\s*|\s+for\s+)([^\n]+)/i,
301→  );
302→  if (headerMatch) {
303→    const numberMatches = headerMatch[1].matchAll(ISSUE_NUMBER_PATTERN);
304→    for (const match of numberMatches) {
305→      const num = parseInt(match[1], 10);
306→      if (!isNaN(num) && !result.issueNumbers.includes(num)) {
307→        result.issueNumbers.push(num);
308→      }
309→    }
310→  }
311→
312→  // Try HTML comment markers first (most reliable, machine-readable)
313→  const markers = parseAssessMarkers(body);
314→
315→  // Action from markers overrides inline detection
316→  if (markers.action) {
317→    result.action = markers.action;
318→  }
319→
320→  if (markers.phases && markers.phases.length > 0) {
321→    result.phases = markers.phases as Phase[];
322→    result.workflowString = markers.phases.join(" → ");
323→  }
324→
325→  if (markers.qualityLoop !== undefined) {
326→    result.qualityLoop = markers.qualityLoop;
327→  }
328→
329→  // If we got phases from markers, we're done with phase detection
330→  if (result.phases.length > 0) {
331→    return result;
332→  }
333→
334→  // Find workflow lines (e.g., "/spec 152" or "spec → exec → qa")
335→  const lines = body.split("\n");
336→
337→  // First pass: look for arrow notation (most reliable)
338→  for (const line of lines) {
339→    if (line.includes("→") || line.includes("->")) {
340→      const phases = parseWorkflowString(line);
341→      if (phases.length > 0) {
342→        result.phases = phases;
343→        result.workflowString = line.trim();
344→        break;
345→      }
346→    }
347→  }
348→
349→  // Second pass: if no arrow notation found, collect phases from multiple lines
350→  if (result.phases.length === 0) {
351→    const collectedPhases: Phase[] = [];
352→
353→    for (const line of lines) {
354→      if (
355→        line.includes("/spec") ||
356→        line.includes("/exec") ||
357→        line.includes("/test") ||
358→        line.includes("/qa")
359→      ) {
360→        const linePhases = parseWorkflowString(line);
361→        for (const phase of linePhases) {
362→          if (!collectedPhases.includes(phase)) {
363→            collectedPhases.push(phase);
364→          }
365→        }
366→      }
367→    }
368→
369→    if (collectedPhases.length > 0) {
370→      result.phases = collectedPhases;
371→      result.workflowString = collectedPhases.map((p) => `/${p}`).join(" → ");
372→    }
373→  }
374→
375→  // If no phases found from lines, try full body
376→  if (result.phases.length === 0) {
377→    result.phases = parseWorkflowString(body);
378→  }
379→
380→  // Check for quality loop recommendation (if not already set by markers)
