 179→/**
 180→ * Parse dependencies from issue body and labels
 181→ * Returns array of issue numbers this issue depends on
 182→ */
 183→export function parseDependencies(issueNumber: number): number[] {
 184→  try {
 185→    const result = spawnSync(
 186→      "gh",
 187→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
 188→      { stdio: "pipe" },
 189→    );
 190→
 191→    if (result.status !== 0) return [];
 192→
 193→    const data = JSON.parse(result.stdout.toString());
 194→    const dependencies: number[] = [];
 195→
 196→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
 197→    if (data.body) {
 198→      const bodyMatch = data.body.match(
 199→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
 200→      );
 201→      if (bodyMatch) {
 202→        for (const match of bodyMatch) {
 203→          const numMatch = match.match(/(\d+)/);
 204→          if (numMatch) {
 205→            dependencies.push(parseInt(numMatch[1], 10));
 206→          }
 207→        }
 208→      }
 209→    }
 210→
 211→    // Parse from labels: "depends-on/123" or "depends-on-123"
 212→    if (data.labels && Array.isArray(data.labels)) {
 213→      for (const label of data.labels) {
 214→        const labelName = label.name || label;
 215→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
 216→        if (labelMatch) {
 217→          dependencies.push(parseInt(labelMatch[1], 10));
 218→        }
 219→      }
 220→    }
 221→
 222→    return [...new Set(dependencies)]; // Remove duplicates
 223→  } catch {
 224→    return [];
 225→  }
 226→}
 227→
 228→/**
 229→ * Sort issues by dependencies (topological sort)
 230→ * Issues with no dependencies come first, then issues that depend on them
 231→ */
 232→export function sortByDependencies(issueNumbers: number[]): number[] {
 233→  // Build dependency graph
 234→  const dependsOn = new Map<number, number[]>();
 235→  for (const issue of issueNumbers) {
 236→    const deps = parseDependencies(issue);
 237→    // Only include dependencies that are in our issue list
 238→    dependsOn.set(
 239→      issue,
 240→      deps.filter((d) => issueNumbers.includes(d)),
 241→    );
 242→  }
 243→
 244→  // Topological sort using Kahn's algorithm
 245→  const inDegree = new Map<number, number>();
 246→  for (const issue of issueNumbers) {
 247→    inDegree.set(issue, 0);
 248→  }
 249→  for (const deps of dependsOn.values()) {
 250→    for (const dep of deps) {
 251→      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
 252→    }
 253→  }
 254→
 255→  // Note: inDegree counts how many issues depend on each issue
 256→  // We want to process issues that have no dependencies first,
 257→  // so dependent issues come after their prerequisites
 258→  const sorted: number[] = [];
 259→  const queue: number[] = [];
 260→
 261→  // Start with issues that have no dependencies
 262→  for (const issue of issueNumbers) {
 263→    const deps = dependsOn.get(issue) || [];
 264→    if (deps.length === 0) {
 265→      queue.push(issue);
 266→    }
 267→  }
 268→
 269→  const visited = new Set<number>();
 270→  while (queue.length > 0) {
 271→    const issue = queue.shift()!;
 272→    if (visited.has(issue)) continue;
 273→    visited.add(issue);
 274→    sorted.push(issue);
 275→
 276→    // Find issues that depend on this one
 277→    for (const [other, deps] of dependsOn.entries()) {
 278→      if (deps.includes(issue) && !visited.has(other)) {
 279→        // Check if all dependencies of 'other' are satisfied
 280→        const allDepsSatisfied = deps.every((d) => visited.has(d));
 281→        if (allDepsSatisfied) {
 282→          queue.push(other);
 283→        }
 284→      }
 285→    }
 286→  }
 287→
 288→  // Add any remaining issues (circular dependencies or unvisited)
 289→  for (const issue of issueNumbers) {
 290→    if (!visited.has(issue)) {
 291→      sorted.push(issue);
 292→    }
 293→  }
 294→
 295→  return sorted;
 296→}
