        phases: ["spec", "exec"],
        qualityLoop: true,
        issueNumbers: [325],
      };
      const signals = assessWorkflowToSignals(workflow);
      expect(signals).toHaveLength(3);
      expect(signals[2]).toEqual({
        phase: "quality-loop",
        source: "assess",
        confidence: "high",
        reason: "Quality loop recommended by /assess command",
      });
    });

    it("should use phase name as fallback when no workflowString", () => {
      const workflow: AssessWorkflowResult = {
        phases: ["exec"],
        qualityLoop: false,
        issueNumbers: [],
      };
      const signals = assessWorkflowToSignals(workflow);
      expect(signals[0].reason).toBe("Recommended by /assess command: exec");
    });
  });

  // === FAILURE PATHS ===
  describe("error handling", () => {
    it("should produce empty signals for empty workflow", () => {
      const signals = assessWorkflowToSignals({
        phases: [],
        qualityLoop: false,
        issueNumbers: [],
      });
      expect(signals).toHaveLength(0);
    });
  });
});

// === AC-13: Backward-compat re-exports from solve-comment-parser.ts ===

describe("backward compatibility re-exports", () => {
  describe("AC-13: solve-comment-parser.ts re-exports", () => {
    it("should export isSolveComment as alias for isAssessComment", () => {
      expect(typeof isSolveComment).toBe("function");
      const body = "## Solve Workflow for Issues: 123\nspec → exec → qa";
      expect(isSolveComment(body)).toBe(true);
      // Also detects new format
      expect(isSolveComment("## Assess Analysis\n→ PROCEED")).toBe(true);
    });

    it("should export findSolveComment as alias for findAssessComment", () => {
      expect(typeof findSolveComment).toBe("function");
      const comments: IssueComment[] = [
        { body: "Regular" },
        { body: "## Solve Workflow for Issues: 123\nspec → exec" },
      ];
      const result = findSolveComment(comments);
      expect(result).not.toBeNull();
    });

    it("should export parseSolveWorkflow as alias for parseAssessWorkflow", () => {
      expect(typeof parseSolveWorkflow).toBe("function");
      const body =
        "## Solve Analysis\n\nspec → exec → qa\n<!-- solve:phases=spec,exec,qa -->";
      const result = parseSolveWorkflow(body);
      expect(result.phases).toEqual(["spec", "exec", "qa"]);
    });

    it("should export parseSolveMarkers as alias for parseAssessMarkers", () => {
      expect(typeof parseSolveMarkers).toBe("function");
      const markers = parseSolveMarkers("<!-- solve:phases=exec,qa -->");
      expect(markers.phases).toEqual(["exec", "qa"]);
    });

    it("should export solveWorkflowToSignals with /solve wording", () => {
      expect(typeof solveWorkflowToSignals).toBe("function");
      const workflow: AssessWorkflowResult = {
        phases: ["spec", "exec", "qa"],
        qualityLoop: false,
        issueNumbers: [123],
        workflowString: "spec → exec → qa",
      };
      const signals = solveWorkflowToSignals(workflow);
      expect(signals).toHaveLength(3);
      // Backward compat: uses "/solve" wording, not "/assess"
      expect(signals[0].reason).toBe(
        "Recommended by /solve command: spec → exec → qa",
      );
    });

    it("should export solveCoversIssue as alias for assessCoversIssue", () => {
      expect(typeof solveCoversIssue).toBe("function");
      const workflow: AssessWorkflowResult = {
        phases: [],
        qualityLoop: false,
        issueNumbers: [123, 456],
      };
      expect(solveCoversIssue(workflow, 123)).toBe(true);
      expect(solveCoversIssue(workflow, 789)).toBe(false);
    });

    it("should export SolveWorkflowResult as type alias", () => {
      // Type compatibility verified at compile time
      const result: SolveWorkflowResult = {
        phases: ["spec"],
        qualityLoop: false,
        issueNumbers: [],
      };
      expect(result.phases).toEqual(["spec"]);
    });

    it("should export SolveMarkers as type alias", () => {
      // Type compatibility verified at compile time
      const markers: SolveMarkers = {
        phases: ["exec"],
        action: "PROCEED",
      };
      expect(markers.phases).toEqual(["exec"]);
    });
  });
});

// === AC-6: /solve alias with deprecation notice ===

describe("solve alias deprecation", () => {
  describe("AC-6: parser handles both old and new formats", () => {
    it("should parse old solve format comments", () => {
      const body =
        "## Solve Analysis\n\n<!-- solve:phases=exec,qa -->\n<!-- solve:quality-loop=true -->";
      const result = parseAssessWorkflow(body);
      expect(result.phases).toEqual(["exec", "qa"]);
      expect(result.qualityLoop).toBe(true);
    });

    it("should parse new assess format comments", () => {
      const body = [
        "## Assess Analysis",
        "",
        "→ PROCEED — Ready for work.",
        "",
        "<!-- assess:phases=spec,exec,qa -->",
        "<!-- assess:action=PROCEED -->",
        "<!-- assess:quality-loop=true -->",
      ].join("\n");
      const result = parseAssessWorkflow(body);
      expect(result.phases).toEqual(["spec", "exec", "qa"]);
      expect(result.action).toBe("PROCEED");
      expect(result.qualityLoop).toBe(true);
    });
  });
});

// === assessCoversIssue ===

describe("assessCoversIssue", () => {
  it("should return true when issue is in the list", () => {
    const workflow: AssessWorkflowResult = {
      phases: [],
      qualityLoop: false,
      issueNumbers: [100, 200, 300],
    };
    expect(assessCoversIssue(workflow, 200)).toBe(true);
  });

  it("should return false when issue is not in the list", () => {
    const workflow: AssessWorkflowResult = {
      phases: [],
      qualityLoop: false,
      issueNumbers: [100, 200],
    };
    expect(assessCoversIssue(workflow, 999)).toBe(false);
  });
});

